// Beat Freq — multiply two close-frequency osc for beating interference
speed = 0.6

AUDIO.bins = 6; AUDIO.smooth = 0.78; AUDIO.gain = 50; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

// mult creates dark/bright interference, NOT mush like blend
osc(20, 0.06, 1.8)
  .mult(osc(21, 0.07, 2.2).rotate(0.4))
  .color(
    () => 1.2 + low() * 1.0,
    () => 0.5 + mid() * 0.8,
    () => 0.2 + high() * 0.6
  )
  .modulate(noise(1.5, 0.2), 0.05)
  .add(osc(5, 0.03, 1.5).color(0.15, 0.1, 0.25), 0.3)
  .blend(src(o0).hue(() => amp() * 0.006).colorama(() => 0.002 + low() * 0.004), 0.8)
  .saturate(() => 1.1 + low() * 0.6)
  .contrast(() => 1.0 + low() * 0.15)
  .brightness(() => 0.04 + low() * 0.03)
  .out(o0)
